select

from logical_plant
where tenant_id = #{tenantId}

  AND logical_plant_no like concat('%',concat('/',#{logicalPlantNo},'%')) ESCAPE '/'


  AND logical_plant_name like concat('%',concat('/',#{logicalPlantName},'%')) ESCAPE '/'


  AND province = #{province}


  AND city = #{city}


  AND region = #{region}

and deleted = 0
order by update_time desc
